import { createRouter, createWebHistory } from 'vue-router'
import HomeView from '@/views/HomeView.vue'

const routes = [
  {
    path: '/',
    name: 'home',
    component: HomeView
  },
  {
    path: '/contact_us',
    name: 'contact',
    // route level code-splitting
    // this generates a separate chunk (about.[hash].js) for this route
    // which is lazy-loaded when the route is visited.
    component: () => import(/* webpackChunkName: "Contact" */ '@/views/ContactView.vue')
  },
  {
    path: '/about_us',
    name: 'aboutus',
    component: () => import(/* webpackChunkName: "AboutUs" */ '@/views/AboutUsView.vue')
  },
  {
    path: '/get_quote',
    name: 'getquote',
    component: () => import(/* webpackChunkName: "GeQuote" */ '@/views/GetQuoteView.vue')
  },
  {
    path: '/product/:prdt_id',
    name: 'product',
    props: true,
    component: () => import(/* webpackChunkName: "PrdtInfo" */ '@/views/PrdtInfoView.vue')
  },
  {
    path: '/service/:service_id',
    name: 'service',
    props: true,
    component: () => import(/* webpackChunkName: "ServiceInfo" */ '@/views/ServiceView.vue')
  }
]


const router = createRouter({
  history: createWebHistory(),
  routes,
  scrollBehavior (to, from, savedPosition) {
      if (savedPosition) {
        return savedPosition
      }else {
        return { top: 0 }
      }
  }
})

export default router
